UPDATE matura_db.algo_tasks SET solution = '#include <bits/stdc++.h>\nusing namespace std;\nint cmpCnt = 0;\nint partition(vector<int>& a, int l, int r){\n    int pivot = a[r], i = l - 1;\n    for(int j = l; j < r; j++){\n        cmpCnt++;\n        if(a[j] <= pivot){ i++; swap(a[i], a[j]); }\n    }\n    swap(a[i+1], a[r]);\n    return i + 1;\n}\nvoid qsort(vector<int>& a, int l, int r){\n    if(l >= r) return;\n    int p = partition(a, l, r);\n    int lo = p, hi = p;\n    while(lo > l && a[lo-1] == a[p]) lo--;\n    while(hi < r && a[hi+1] == a[p]) hi++;\n    qsort(a, l, lo - 1);\n    qsort(a, hi + 1, r);\n}\nint main(){\n    int n; cin >> n;\n    vector<int> a(n);\n    for(int i = 0; i < n; i++) cin >> a[i];\n    qsort(a, 0, n - 1);\n    for(int i = 0; i < n; i++){\n        if(i) cout << " ";\n        cout << a[i];\n    }\n    cout << "\\\\n" << cmpCnt << endl;\n    return 0;\n}' WHERE id = 37;
