SELECT 'algo_tasks' AS tbl, COUNT(*) AS cnt FROM matura_db.algo_tasks
UNION ALL
SELECT 'algo_task_tests', COUNT(*) FROM matura_db.algo_task_tests
UNION ALL
SELECT 'quiz_questions', COUNT(*) FROM matura_db.quiz_questions;
